"""
MKT Christ Commentary — Isaiah 48 (22 verses — The Stubborn Servant / Come Out of Babylon)
Run: python3 scripts/zc-christ-isaiah-48.py
Key decisions:
- v12: "I am He, I am the First and I am the Last" — DIRECT title claimed by
  Christ in Rev 1:17 ("I am the First and the Last") and Rev 2:8; Christ
  explicitly appropriates the YHWH self-identification of Isaiah 48:12
- v16: "And now the Lord GOD has sent me, and his Spirit" — the clearest
  Trinitarian statement embedded in the Servant's own speech: the Servant
  is sent by the Lord YHWH, accompanied by the Spirit; anticipates the
  Johannine Farewell Discourse (John 14:26, 15:26, 16:7)
- v10: Refining in the furnace of affliction — 1 Pet 1:7 (trials refine
  faith like gold); the suffering that purifies
- v17-19: "I am the LORD your God... if only you had listened" — the
  counterfactual shalom; the peace like a river that disobedience forfeited;
  contrast with John 14:27 (Christ's gift of peace not as the world gives)
- v20: "Go out from Babylon, flee from Chaldea" — the exodus call; fulfilled
  in the gospel's call out of the world-system (Rev 18:4: "Come out of her,
  my people"); the new exodus that Christ inaugurates
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent


def load_comm(layer, book):
    p = ROOT / "data" / "commentary" / layer / f"{book}.json"
    return json.loads(p.read_text()) if p.exists() else {}


def save_comm(layer, book, data):
    p = ROOT / "data" / "commentary" / layer / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=2))


def merge_comm(existing, new_data):
    # INTENT: Write only absent keys so re-running is safe after manual edits.
    # CHANGE? If isaiah.json schema changes, update merge_comm and ISAIAH dict below.
    # VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-christ/
    #   isaiah.json')); print('Isa 48 v12:',d.get('48',{}).get('12','MISSING')[:80])"
    for ch, verses in new_data.items():
        existing.setdefault(ch, {})
        for v, text in verses.items():
            existing[ch].setdefault(v, text)


ISAIAH = {
    "48": {
        "1": "<p>\"Hear this, O house of Jacob, who are called by the name of Israel, and who came from the waters of Judah, who swear by the name of the LORD and confess the God of Israel, but not in truth or right\" — the indictment against formal religion: the people who use the right name, take the right oaths, and confess the right God, but whose allegiance is \"not in truth or right\" (<em>wĕlōʾ beʾĕmet ûbitsĕdāqāh</em>). Matthew 15:8: \"'These people honor me with their lips, but their hearts are far from me.'\" (quoting Isaiah 29:13). The gap between religious profession and genuine faith that Isaiah 48:1 diagnoses is the gap that Christ repeatedly confronts in the Gospels — the Pharisees who swear by the Temple but whose hearts are far from God (Matt 23:16-22). Romans 2:28-29: \"A person is not a Jew who is one only outwardly... No, a person is a Jew who is one inwardly; and circumcision is circumcision of the heart.\" Isaiah 48:1's critique of nominal covenant allegiance is the foundation of the NT's insistence on heart-transformation through Christ.</p>",
        "2": "<p>\"For they call themselves after the holy city, and stay themselves on the God of Israel; the LORD of hosts is his name\" — the people who identify with Jerusalem and lean on YHWH, but without the genuine trust that would make the leaning productive. The title \"LORD of hosts\" (<em>YHWH tsĕbāʾôt</em>) is invoked ironically — the one whose name they invoke is the one whose patience they are exhausting. Revelation 3:1: \"I know your deeds; you have a reputation of being alive, but you are dead.\" The Sardis church has the name of life without its reality — the same structural gap as Isaiah 48:2. Revelation 2:9: \"I know the blasphemy of those who say they are Jews and are not, but are a synagogue of Satan.\" The NT identifies those who wear the covenant name without covenant allegiance as the continuing problem that Israel's history diagnosed and Christ definitively addresses through the new birth (John 3:3).</p>",
        "3": "<p>\"The former things I declared of old; they went out from my mouth and I announced them; then suddenly I did them, and they came to pass\" — the argument from fulfilled prophecy: YHWH declared the former things, they came to pass. This is the evidential basis for trusting the new announcements. 2 Peter 1:19-21: \"We also have the prophetic message as something completely reliable, and you will do well to pay attention to it... For prophecy never had its origin in the human will, but prophets, though human, spoke from God as they were carried along by the Holy Spirit.\" The \"declared... suddenly done\" pattern of Isaiah 48:3 is Peter's argument for the reliability of prophecy: the track record of fulfilled prediction authorizes trust in unfulfilled prediction. The resurrection is the supreme instance of the \"suddenly I did them\" pattern — announced in the Law, Prophets, and Psalms (Luke 24:44-45), suddenly accomplished.</p>",
        "4": "<p>\"Because I know that you are obstinate, and your neck is an iron sinew and your forehead brass\" — the divine assessment of Israel's stubbornness: iron-sinew neck (unbending pride) and brass forehead (brazen shamelessness). The anatomy of rebellion. Acts 7:51: \"You stiff-necked people! Your hearts and ears are still uncircumcised. You are just like your ancestors: You always resist the Holy Spirit!\" Stephen's speech to the Sanhedrin quotes the vocabulary of Isaiah 48:4 — the stiff-necked people who resisted the Spirit have always been present in covenant history. Hebrews 3:8: \"do not harden your hearts as you did in the rebellion, during the time of testing in the wilderness.\" Christ's ministry is the definitive test of Israel's stiffneckedness — and the resurrection that followed the rejection was YHWH's response to brass-foreheaded obstinacy: not capitulation but vindication of the rejected Son.</p>",
        "5": "<p>\"I declared them to you from of old, before they came to pass I announced them to you, lest you should say, 'My idol did them, my carved image and my cast image commanded them'\" — the purpose of predictive prophecy: to preempt idol-attribution. YHWH announces events before they happen so that when they occur, the idol-worshiper cannot claim credit for the idol. John 13:19: \"I am telling you this now, before it takes place, that when it does take place you may believe that I am he.\" John 14:29: \"I have told you now before it happens, so that when it does happen you will believe.\" Jesus uses the same evidential logic of Isaiah 48:5 — he predicts events (his betrayal, death, resurrection, the Spirit's coming) precisely so that their fulfillment will generate faith rather than confusion. Predictive prophecy is a pastoral tool: foreknowledge shared now becomes faith-confirming evidence later.</p>",
        "6": "<p>\"You have heard; now see all this; and will you not declare it? From this time forth I announce to you new things, hidden things that you have not known\" — the hinge: from past-fulfillment-argument to new-announcement. The \"new things\" that are now declared are hidden, unprecedented. 1 Corinthians 2:7-9: \"No, we declare God's wisdom, a mystery that has been hidden and that God destined for our glory before time began. None of the rulers of this age understood it... 'What no eye has seen, what no ear has heard, and what no human mind has conceived — the things God has prepared for those who love him.'\" The \"hidden things\" of Isaiah 48:6 are the mystery of Christ (Col 1:26-27: \"the mystery that has been kept hidden for ages and generations, but is now disclosed to the Lord's people... Christ in you, the hope of glory\"). The new-thing announcement moves from Cyrus (the near fulfillment) to Christ (the ultimate fulfillment).</p>",
        "7": "<p>\"They are created now, not long ago; before today you have never heard of them, lest you should say, 'Behold, I knew them'\" — the utter novelty of the new things: created now, not recoverable from the past. No one can claim prior knowledge. 1 Corinthians 1:18-21: \"For the message of the cross is foolishness to those who are perishing... For the foolishness of God is wiser than human wisdom, and the weakness of God is stronger than human strength.\" The wisdom of the cross is the Isaiah 48:7 new thing — no one anticipated a crucified Messiah, which is why the rulers of the world crucified the Lord of glory (1 Cor 2:8). The novelty that prevents prior-knowledge claims is precisely the stumbling-block character of the cross: it was not the fulfillment of human wisdom or expectation but the new creation of divine wisdom.</p>",
        "8": "<p>\"You have never heard, you have never known, from of old your ear has not been opened. For I knew that you would surely deal treacherously, and that from before birth you were called a rebel\" — the pre-birth rebel designation: YHWH knew Israel's treachery before it happened and still called them. The election-despite-foreknown-sin is the foundation of grace. Romans 9:11-12: \"Yet, before the twins were born or had done anything good or bad — in order that God's purpose in election might stand: not by works but by him who calls — she was told, 'The older will serve the younger.'\" Romans 5:8: \"But God demonstrates his own love for us in this: While we were still sinners, Christ died for us.\" The \"called a rebel from before birth\" of Isaiah 48:8 is the context in which divine love operates — not love for the worthy but for the foreknown sinner, which is why the cross is the ultimate expression of grace rather than merit.</p>",
        "9": "<p>\"For my name's sake I defer my anger; for the sake of my praise I restrain it for you, that I may not cut you off\" — the divine self-restraint grounded in the divine name: YHWH does not judge Israel immediately because doing so would compromise his own name and praise. The logic of Ezekiel 36:22: \"It is not for your sake, people of Israel, that I am going to do these things, but for the sake of my holy name.\" Romans 3:25-26: \"He did this to demonstrate his righteousness, because in his forbearance he had left the sins committed beforehand unpunished — he did it to demonstrate his righteousness at the present time, so as to be just and the one who justifies those who have faith in Jesus.\" The divine restraint of Isaiah 48:9 and the divine forbearance of Romans 3:25 are resolved at the same place: the cross, where YHWH's anger against sin is discharged in Christ rather than deferred indefinitely, and his name/praise is vindicated rather than compromised.</p>",
        "10": "<p>\"Behold, I have refined you, but not as silver; I have tried you in the furnace of affliction\" — the refining image: trial in the furnace of affliction (<em>kûr ʿōnî</em>), but not the standard silver-refining process — a different, harder refining. 1 Peter 1:6-7: \"In all this you greatly rejoice, though now for a little while you may have had to suffer grief in all kinds of trials. These have come so that the proven genuineness of your faith — of greater worth than gold, which perishes even though refined by fire — may result in praise, glory and honor when Jesus Christ is revealed.\" James 1:3: \"because you know that the testing of your faith produces perseverance.\" The furnace of affliction that refined Israel (Isaiah 48:10) is the furnace of trial that refines faith in the NT — and the supreme refiner is Christ who himself was tried in the ultimate furnace (Heb 2:18: \"Because he himself suffered when he was tempted, he is able to help those who are being tempted\").</p>",
        "11": "<p>\"For my own sake, for my own sake, I do it, for how should my name be profaned? My glory I will not give to another\" — the double divine self-motivation: \"for my own sake, for my own sake\" (<em>lĕmaʿănî lĕmaʿănî</em>). The salvation of the exiles is not primarily for their benefit but for the vindication of YHWH's name and glory. Ezekiel 36:22-23: \"It is not for your sake, Israel, that I am going to do these things, but for the sake of my holy name.\" John 17:1: \"Father, the hour has come. Glorify your Son, that your Son may glorify you.\" Philippians 2:9-11: \"Therefore God exalted him to the highest place and gave him the name that is above every name, that at the name of Jesus every knee should bow... to the glory of God the Father.\" The \"my glory I will not give to another\" of Isaiah 48:11 is the logic of the incarnation: YHWH's glory is not given to another — it is expressed through the Son who is not another but is YHWH himself, so that the Son's exaltation is YHWH's glory.</p>",
        "12": "<p>\"Listen to me, O Jacob, and Israel, whom I called! I am he; I am the first, and I am the last\" — the divine self-declaration: \"I am the First and I am the Last\" (<em>ʾănî rīʾšôn ʾap ʾănî ʾaḥărôn</em>). Revelation 1:17: \"When I saw him, I fell at his feet as though dead. Then he placed his right hand on me and said: 'Do not be afraid. I am the First and the Last.'\" Revelation 2:8: \"These are the words of him who is the First and the Last, who died and came to life again.\" Revelation 22:13: \"I am the Alpha and the Omega, the First and the Last, the Beginning and the End.\" The DIRECT identification of Christ with the Isaiah 48:12 title is unambiguous: the risen Christ appropriates the divine self-declaration of YHWH-to-Israel, claiming the full divine identity. This is one of the strongest Christological titles in Revelation, grounded in Second Isaiah's exclusive monotheism.</p>",
        "13": "<p>\"My hand laid the foundation of the earth, and my right hand spread out the heavens; when I call to them, they stand forth together\" — the creator-identity of the First and Last: the one who claims the eternal titles (v12) is the same one whose hand founded the earth and whose voice summons the creation into order. Hebrews 1:10-12: \"He also says, 'In the beginning, Lord, you laid the foundations of the earth, and the heavens are the work of your hands. They will perish, but you remain; they will all wear out like a garment. You will roll them up like a robe; like a garment they will be changed. But you remain the same, and your years will never end.'\" Hebrews applies this creation-language directly to the Son. John 1:3: \"Through him all things were made; without him nothing was made that has been made.\" The hand that laid earth's foundation in Isaiah 48:13 is the Word of John 1 and the Son of Hebrews 1 — creator-identity belonging to the one who is also the risen Christ of Revelation 1:17.</p>",
        "14": "<p>\"Come together, all of you, and listen! Who among the gods has declared these things? The LORD loves him; he shall perform his purpose on Babylon, and his arm shall be against the Chaldeans\" — the gathering of all to hear the announcement of Cyrus's coming conquest of Babylon (\"he whom the LORD loves\" = Cyrus). The rhetorical challenge — which god predicted this? — is the cosmic trial from chapter 43. Acts 2:23: \"This man was handed over to you by God's deliberate plan and foreknowledge; and you, with the help of wicked men, put him to death by nailing him to the cross.\" The Cyrus-announcement is a type of the Christ-announcement: both are declared before they occur, both accomplish YHWH's purpose through unexpected instruments, and both demonstrate that YHWH — not Marduk, not fate — controls history. The arm that moves against Babylon (v14) is the arm that bore Isaiah 53:1 — the same divine power that releases exiles and redeems sinners.</p>",
        "15": "<p>\"I, even I, have spoken and called him; I have brought him and he will succeed in his mission\" — the divine double-claim of initiative: \"I, even I\" (<em>ʾănî ʾănî dibbartî</em>). YHWH takes personal responsibility for Cyrus's call and success. The pattern of divine initiative that guarantees mission-success is the pattern of every divine sending. John 6:37-39: \"All those the Father gives me will come to me, and whoever comes to me I will never drive away. For I have come down from heaven not to do my will but to do the will of him who sent me. And this is the will of him who sent me, that I shall lose none of all those he has given me, but raise them up at the last day.\" The \"I have brought him and he will succeed\" of Isaiah 48:15 is the ground of the Johannine mission-security: the Son sent by the Father will not fail, will lose none, will accomplish exactly what the Father purposed. Divine initiative guarantees mission completion.</p>",
        "16": "<p>\"Draw near to me, hear this: from the beginning I have not spoken in secret, from the time it was, there I was. And now the Lord GOD has sent me, and his Spirit\" — the most explicit Trinitarian statement in Isaiah: the Servant speaks in the first person (\"me,\" \"I was\") and then announces that \"the Lord GOD has sent me, and his Spirit\" — three parties: the Servant who speaks, the Lord GOD who sends, and the Spirit who accompanies. John 14:26: \"But the Advocate, the Holy Spirit, whom the Father will send in my name, will teach you all things.\" John 15:26: \"When the Advocate comes, whom I will send to you from the Father — the Spirit of truth who goes out from the Father — he will testify about me.\" John 16:7: \"unless I go away, the Advocate will not come to you; but if I go, I will send him to you.\" Isaiah 48:16 in the Servant's voice maps onto the Johannine Farewell Discourse: Servant sent by Father, Spirit accompanying — the same Trinitarian structure.</p>",
        "17": "<p>\"Thus says the LORD, your Redeemer, the Holy One of Israel: 'I am the LORD your God, who teaches you to profit, who leads you in the way you should go'\" — the covenant God who teaches and leads: <em>mĕlammēdĕkā lĕhôʿîl</em> (teaches you to profit/succeed). John 14:26: \"But the Advocate, the Holy Spirit, whom the Father will send in my name, will teach you all things and will remind you of everything I have said to you.\" John 16:13: \"But when he, the Spirit of truth, comes, he will guide you into all the truth.\" The teaching-leading God of Isaiah 48:17 becomes the teaching-guiding Spirit of John 14-16 — the same divine instruction now given through the Spirit of Christ. Hebrews 12:10-11: \"God disciplines us for our good, in order that we may share in his holiness. No discipline seems pleasant at the time, but painful. Later on, however, it produces a harvest of righteousness and peace for those trained by it.\" The teaching that \"profits\" is the discipline of the Father through the Son.</p>",
        "18": "<p>\"Oh that you had paid attention to my commandments! Then your peace would have been like a river, and your righteousness like the waves of the sea\" — the counterfactual shalom: the river-peace and sea-righteousness that obedience would have brought. The \"oh that\" (<em>lû</em>) is a wishful particle expressing divine longing. Jeremiah 6:16: \"This is what the LORD says: 'Stand at the crossroads and look; ask for the ancient paths, ask where the good way is, and walk in it, and you will find rest for your souls. But you said, \"We will not walk in it.\"'\" Luke 19:41-42: \"As he approached Jerusalem and saw the city, he wept over it and said, 'If you, even you, had only known on this day what would bring you peace — but now it is hidden from your eyes.'\" Jesus's tears over Jerusalem echo Isaiah 48:18's divine lament — the same God who said \"oh that\" to exilic Israel says it again over first-century Jerusalem. John 14:27: \"Peace I leave with you; my peace I give you.\" Christ gives the river-peace that disobedience forfeited.</p>",
        "19": "<p>\"Your offspring would have been like the sand, and your descendants like its grains; their name would never be cut off or destroyed from before me\" — the forfeited fruitfulness: the Abrahamic promise of numberless descendants (Gen 22:17) conditioned on obedience. The sand-descendants that Israel forfeited through disobedience. Galatians 3:29: \"If you belong to Christ, then you are Abraham's seed, and heirs according to the promise.\" Romans 4:18: \"Against all hope, Abraham in hope believed and so became the father of many nations.\" In Christ, the forfeited promise is restored — but the descendant who inherits it is primarily Christ himself (Gal 3:16: \"The promises were spoken to Abraham and to his seed. Scripture does not say 'and to seeds,' meaning many people, but 'and to your seed,' meaning one person, who is Christ\"). The sand-offspring of Isaiah 48:19 is realized in the innumerable multitude of Revelation 7:9 — those who are in Christ, the one Seed.</p>",
        "20": "<p>\"Go out from Babylon, flee from Chaldea, declare this with a shout of joy, proclaim it, send it out to the end of the earth; say, 'The LORD has redeemed his servant Jacob!'\" — the exodus-call: leave Babylon, announce the redemption. Revelation 18:4: \"Then I heard another voice from heaven say: 'Come out of her, my people, so that you will not share in her sins, so that you will not receive any of her plagues.'\" The Revelation 18:4 call to \"come out of Babylon\" is the NT's direct application of Isaiah 48:20 to the cosmic Babylon — the world-system that holds the people of God captive. 2 Corinthians 6:17: \"'Come out from them and be separate,' says the Lord.\" The gospel as the new-exodus announcement: YHWH has redeemed his servant — go out, shout it, send it to the ends of the earth. Matthew 28:19-20: the Great Commission is the Isaiah 48:20 proclamation extended to all nations — the shout that goes to the end of the earth.</p>",
        "21": "<p>\"They did not thirst when he led them through the deserts; he made water flow for them from the rock; he split the rock and the water gushed out\" — the wilderness-water miracle recalled: the Exodus rock-water (Exod 17:6; Num 20:11) as the type of what the new exodus will provide. 1 Corinthians 10:4: \"and drank from the spiritual rock that accompanied them, and that rock was Christ.\" Paul's identification of the Exodus rock as Christ is the definitive Christological reading of Isaiah 48:21 — the water that gushed from the rock in the wilderness was the pre-incarnate provision of the one who would later say \"I am the living water\" (John 4:10, 7:37-38: \"Let anyone who is thirsty come to me and drink... rivers of living water will flow from within them\"). The new exodus thirst-quenching is Christ himself — not a new rock but the same spiritual rock recognized now by name.</p>",
        "22": "<p>\"There is no peace, says the LORD, for the wicked\" — the counterpoint that closes the chapter and forms a structural refrain (repeated in 57:21): peace is not for those who remain in the Babylon-allegiance of vv1-5. The chapter opened with nominal-covenant people (v1-2) and closes with the reminder that peace belongs only to those who genuinely depart (v20). Romans 3:17: \"the way of peace they do not know.\" Ephesians 2:17: \"He came and preached peace to you who were far away and peace to those who were near.\" Romans 5:1: \"Therefore, since we have been justified through faith, we have peace with God through our Lord Jesus Christ.\" The \"no peace for the wicked\" of Isaiah 48:22 is the excluded middle — between the \"come out\" of v20 and the peace-like-a-river of v18, there is no third option. Christ is the only path to the river-peace: outside of him the Isaiah 48:22 verdict stands.</p>"
    }
}


def main():
    existing = load_comm("mkt-christ", "isaiah")
    before = sum(len(v) for v in existing.values())
    merge_comm(existing, ISAIAH)
    after = sum(len(v) for v in existing.values())
    save_comm("mkt-christ", "isaiah", existing)
    print(f"{len(existing)} chapters, {after} verse entries total (+{after - before} new)")
    for v, kw in [("12", "First"), ("16", "Spirit"), ("20", "Babylon"), ("22", "peace")]:
        entry = existing.get("48", {}).get(v, "MISSING")
        print(f"  Isa 48:{v} — {'OK' if kw.lower() in entry.lower() else 'CHECK'}")
    ch = existing.get("48", {})
    missing = [str(i) for i in range(1, 23) if str(i) not in ch]
    print(f"  Missing verses: {missing if missing else 'none'}")


if __name__ == "__main__":
    main()
